/* heap.msw -- SNOBOL4 Heap Object Header Layout for COR24
 *
 * Every heap object starts with a uniform 2-word (6-byte) header.
 *
 * Word 0 (3 bytes):
 *   byte 0: object kind     (OBJ_KIND)
 *   byte 1: GC mark + flags (OBJ_MARK_FLAGS)
 *     bit 7: GC mark bit
 *     bit 6: pinned (not movable)
 *     bits 0-5: kind-specific flags
 *   byte 2: reserved        (OBJ_RSV)
 *
 * Word 1 (3 bytes):
 *   bytes 3-5: size in bytes including header (OBJ_SIZE)
 *
 * Objects are contiguous in the heap. The heap walker advances
 * by reading OBJ_SIZE at each header to find the next object.
 *
 * Physical layout is COR24-specific; the walker and dumper
 * depend on these conventions.
 */

/* --- Object kind constants (byte 0) --- */

%DEFINE OBK_FREE     0;
%DEFINE OBK_STRING   1;
%DEFINE OBK_SYMCELL  2;
%DEFINE OBK_PATNODE  3;
%DEFINE OBK_BTFRAME  4;
%DEFINE OBK_RBENTRY  5;
%DEFINE OBK_CODEBLK  6;
%DEFINE OBK_ARRAY    7;
%DEFINE OBK_TABLE    8;
%DEFINE OBK_COUNT    9;

/* --- GC / flag bits (byte 1) --- */

%DEFINE OBF_MARK     128;
%DEFINE OBF_PINNED   64;

/* --- Header size --- */

%DEFINE HDR_BYTES    6;
%DEFINE HDR_WORDS    2;

/* --- Header as BASED record --- */

DCL 1 OBJHDR BASED,
    3 OKIND   BYTE,
    3 OFLAGS  BYTE,
    3 ORSV    BYTE,
    3 OSIZE   PTR;

/* --- Header access macros ---
 *
 * ?OBJ_KIND: read object kind byte
 *   Input:  PTR(expr) -- pointer to object header
 *   Output: r0 = kind byte
 *   Clobbers: r0, r2
 */

MACRODEF OBJ_KIND;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,0(r2)';
    END;
END;

MACRODEF OBJ_SET_KIND;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{VAL}';
        'sb      r0,0(r2)';
    END;
END;

/* ?OBJ_FLAGS: read flags byte (includes GC mark)
 *   Input:  PTR(expr) -- pointer to object header
 *   Output: r0 = flags byte
 *   Clobbers: r0, r2
 */

MACRODEF OBJ_FLAGS;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,1(r2)';
    END;
END;

MACRODEF OBJ_SET_FLAGS;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{VAL}';
        'sb      r0,1(r2)';
    END;
END;

/* ?OBJ_SIZE: read object size (24-bit, includes header)
 *   Input:  PTR(expr) -- pointer to object header
 *   Output: r0 = size in bytes
 *   Clobbers: r0, r2
 */

MACRODEF OBJ_SIZE;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lw      r0,3(r2)';
    END;
END;

MACRODEF OBJ_SET_SIZE;
    REQUIRED PTR(expr);
    REQUIRED VAL(expr);
    GEN DO;
        'la      r2,{PTR}';
        'la      r0,{VAL}';
        'sw      r0,3(r2)';
    END;
END;

/* --- Header construction macro ---
 *
 * ?BUILD_HDR: initialize a heap object header
 *   Input:  PTR(expr)  -- pointer to header location
 *           KIND(expr) -- object kind constant
 *           SIZE(expr) -- total object size in bytes (including header)
 *   Clobbers: r0, r2
 */

MACRODEF BUILD_HDR;
    REQUIRED PTR(expr);
    REQUIRED KIND(expr);
    REQUIRED SIZE(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lc      r0,{KIND}';
        'sb      r0,0(r2)';
        'lc      r0,0';
        'sb      r0,1(r2)';
        'sb      r0,2(r2)';
        'la      r0,{SIZE}';
        'sw      r0,3(r2)';
    END;
END;

/* --- GC mark macros ---
 *
 * ?OBJ_SET_MARK: set the GC mark bit
 *   Input:  PTR(expr) -- pointer to object header
 *   Clobbers: r0, r2
 *
 * ?OBJ_CLR_MARK: clear the GC mark bit
 *   Input:  PTR(expr) -- pointer to object header
 *   Clobbers: r0, r2
 *
 * ?OBJ_IS_MARKED: load flags into r0 for mark bit test
 *   Input:  PTR(expr) -- pointer to object header
 *   Output: r0 = flags byte (test bit 7)
 *   Clobbers: r0, r2
 */

MACRODEF OBJ_SET_MARK;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,1(r2)';
        'or      r0,128';
        'sb      r0,1(r2)';
    END;
END;

MACRODEF OBJ_CLR_MARK;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,1(r2)';
        'and     r0,127';
        'sb      r0,1(r2)';
    END;
END;

MACRODEF OBJ_IS_MARKED;
    REQUIRED PTR(expr);
    GEN DO;
        'la      r2,{PTR}';
        'lb      r0,1(r2)';
        'and     r0,128';
    END;
END;

/* --- Heap object payload templates ---
 *
 * These BASED records describe the payload that follows
 * the 6-byte header for each object kind.
 */

/* String object: header + length + character data
 * Total size = HDR_BYTES + 3 + strlen (rounded up if needed)
 */
DCL 1 STROBJ BASED,
    3 SHDR_KIND  BYTE,
    3 SHDR_FLAGS BYTE,
    3 SHDR_RSV   BYTE,
    3 SHDR_SIZE  PTR,
    3 SLEN       PTR,
    3 SDATA(1)   CHAR;

/* Symbol cell: header + name pointer + value descriptor
 * Total size = HDR_BYTES + 3 + DESC_BYTES = 15
 */
DCL 1 SYMOBJ BASED,
    3 YHDR_KIND  BYTE,
    3 YHDR_FLAGS BYTE,
    3 YHDR_RSV   BYTE,
    3 YHDR_SIZE  PTR,
    3 YNAME      PTR,
    3 YVAL_TAG   BYTE,
    3 YVAL_SUB   BYTE,
    3 YVAL_RSV   BYTE,
    3 YVAL_PAY   PTR;

/* Free block: header only, size field gives block extent */
/* (no additional fields beyond the standard header) */

