/* descr.msw -- Descriptor layout (2-word, 6-byte)
 * Word 0: tag(b0) sub(b1) rsv(b2)
 * Word 1: payload(b3-5) -- int, ptr, or id
 */

/* Tag constants */
DCL TAG_NULL INT STATIC INIT(0);
DCL TAG_UNINIT INT STATIC INIT(1);
DCL TAG_INT INT STATIC INIT(2);
DCL TAG_STR INT STATIC INIT(3);
DCL TAG_SYM INT STATIC INIT(4);
DCL TAG_PAT INT STATIC INIT(5);
DCL TAG_LABEL INT STATIC INIT(6);
DCL TAG_BUILTIN INT STATIC INIT(7);
DCL TAG_REAL INT STATIC INIT(8);
DCL TAG_ARRAY INT STATIC INIT(9);
DCL TAG_TABLE INT STATIC INIT(10);
DCL TAG_COUNT INT STATIC INIT(11);

/* Descriptor flag bits (in sub byte) */
DCL DFLAG_FWD INT STATIC INIT(128);
DCL DFLAG_IMMUT INT STATIC INIT(64);

/* Descriptor size */
DCL DESC_BYTES INT STATIC INIT(6);
DCL DESC_WORDS INT STATIC INIT(2);

/* BASED record for pointer access */
DCL 1 DESCR BASED,
    3 DTAG BYTE,
    3 DSUB BYTE,
    3 DRSV BYTE,
    3 DPAY PTR;

/* Inline asm macros for hot-path descriptor access */

/* DESC_COPY: copy 6 bytes. Clobbers r0,r1,r2 */
MACRODEF DESC_COPY;
    REQUIRED DST(expr); REQUIRED SRC(expr);
    GEN DO;
        'la r1,{SRC}'; 'la r2,{DST}';
        'lb r0,0(r1)'; 'sb r0,0(r2)';
        'lb r0,1(r1)'; 'sb r0,1(r2)';
        'lb r0,2(r1)'; 'sb r0,2(r2)';
        'lw r0,3(r1)'; 'sw r0,3(r2)';
    END;
END;

/* BUILD_NULL: zero a descriptor. Clobbers r0,r2 */
MACRODEF BUILD_NULL;
    REQUIRED PTR(expr);
    GEN DO;
        'la r2,{PTR}'; 'lc r0,0';
        'sb r0,0(r2)'; 'sb r0,1(r2)';
        'sb r0,2(r2)'; 'sw r0,3(r2)';
    END;
END;

