DCL OBF_PINNED INT STATIC INIT(64);

/* Header size */
DCL HDR_BYTES INT STATIC INIT(6);
DCL HDR_WORDS INT STATIC INIT(2);

/* BASED record */
DCL 1 OBJHDR BASED,
    3 OKIND BYTE,
    3 OFLAGS BYTE,
    3 ORSV BYTE,
    3 OSIZE PTR;

/* String object: header + length + char data */
DCL 1 STROBJ BASED,
    3 SHDR_KIND BYTE, 3 SHDR_FLAGS BYTE, 3 SHDR_RSV BYTE,
    3 SHDR_SIZE PTR,
    3 SLEN PTR,
    3 SDATA(1) CHAR;

