    DPTR->DPAY = V;
END;

/* --- Helper: copy descriptor (6 bytes) via BASED --- */
DESC_CPY: PROC(D PTR, S PTR);
    DCL DP PTR;
    DCL SP PTR;
    DP = D;
    SP = S;
    DP->DTAG = SP->DTAG;
    DP->DSUB = SP->DSUB;
    DP->DRSV = SP->DRSV;
    DP->DPAY = SP->DPAY;
END;

/* --- Helper: init heap header --- */
HDR_INIT: PROC(P PTR, K INT, SZ INT);
    DCL HP PTR;
    HP = P;
    HP->OKIND = K;
    HP->OFLAGS = 0;
    HP->ORSV = 0;
    HP->OSIZE = SZ;
END;

/* --- Main --- */
MAIN: PROC;
    DCL DPTR PTR;
    DCL HPTR PTR;
    DCL OK INT;

    /* Test 1: null descriptor */
    CALL DESC_INIT(ADDR(D1), TAG_NULL, 0, 0);
    DPTR = ADDR(D1);
    OK = 0;
    IF (DPTR->DTAG = TAG_NULL) THEN
        IF (DPTR->DPAY = 0) THEN
            OK = 1;
    CALL REPORT(OK, ADDR(M_T1));

    /* Test 2: integer descriptor */
    CALL DESC_INIT(ADDR(D2), TAG_INT, 0, 42);
    DPTR = ADDR(D2);
    OK = 0;
    IF (DPTR->DTAG = TAG_INT) THEN
        IF (DPTR->DPAY = 42) THEN
            OK = 1;
    CALL REPORT(OK, ADDR(M_T2));

    /* Test 3: copy descriptor */
    CALL DESC_CPY(ADDR(D3), ADDR(D2));
    DPTR = ADDR(D3);
    OK = 0;
    IF (DPTR->DTAG = TAG_INT) THEN
        IF (DPTR->DPAY = 42) THEN
            OK = 1;
    CALL REPORT(OK, ADDR(M_T3));

    /* Test 4: heap header */
    CALL HDR_INIT(ADDR(FAKEHEAP), OBK_STRING, 24);
    HPTR = ADDR(FAKEHEAP);
    OK = 0;
    IF (HPTR->OKIND = OBK_STRING) THEN
        IF (HPTR->OSIZE = 24) THEN
            OK = 1;
    CALL REPORT(OK, ADDR(M_T4));

    /* Test 5: flags field (using OBF_PINNED=64, <128 avoids lb sign bug plsw#8) */
    HPTR = ADDR(FAKEHEAP);
    HPTR->OFLAGS = OBF_PINNED;
    OK = 0;
    IF (HPTR->OFLAGS = OBF_PINNED) THEN
        OK = 1;
    CALL REPORT(OK, ADDR(M_T5));

    CALL UART_PUTS(ADDR(M_DONE));
    CALL UART_PUTS(ADDR(M_NL));
END;
